export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  // Normalize to remove accents where possible
  const normalized = s.normalize ? s.normalize('NFKD').replace(/\p{M}/gu, '') : s;
  const slug = normalized
    .toLowerCase()
    .replace(/[^0-9a-z]+/g, '-') // replace non-alphanumeric with hyphen
    .replace(/^-+|-+$/g, '') // trim hyphens
    .replace(/-+/g, '-');
  return slug;
}

export function truncate(input, length, suffix = '…') {
  const s = toStr(input);
  if (!s) return "";
  const maxLen = Number(length) || 0;
  if (maxLen <= 0) return '';
  if (s.length <= maxLen) return s;
  const suf = toStr(suffix);
  const allowed = Math.max(0, maxLen - suf.length);
  if (allowed === 0) return suf.slice(0, maxLen);
  const words = s.split(/\s+/);
  let out = '';
  for (let i = 0; i < words.length; i++) {
    const word = words[i];
    if (!out) {
      if (word.length > allowed) {
        out = word.slice(0, allowed);
        break;
      }
      out = word;
    } else {
      if (out.length + 1 + word.length > allowed) break;
      out = out + ' ' + word;
    }
  }
  return out + suf;
}

export function camelCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const parts = s.split(/[^0-9\p{L}]+/u).filter(Boolean);
  if (!parts.length) return '';
  const first = parts[0].toLowerCase();
  const rest = parts.slice(1).map(p => p.charAt(0).toUpperCase() + p.slice(1).toLowerCase());
  return first + rest.join('');
}

export function kebabCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  const parts = s
    .normalize ? s.normalize('NFKD').replace(/\p{M}/gu, '') : s;
  return parts
    .toLowerCase()
    .split(/[^0-9a-z\p{L}]+/u)
    .filter(Boolean)
    .join('-');
}

export function titleCase(input) {
  const s = toStr(input).trim();
  if (!s) return "";
  return s.split(/\s+/).map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (!s) return "";
  const w = Math.max(1, Number(width) || 80);
  const words = s.split(/\s+/);
  const lines = [];
  let current = '';
  for (const word of words) {
    if (!current) {
      if (word.length <= w) current = word;
      else {
        // word longer than width -> put on its own line
        lines.push(word);
        current = '';
      }
    } else {
      if (current.length + 1 + word.length <= w) {
        current += ' ' + word;
      } else {
        lines.push(current);
        if (word.length <= w) current = word;
        else {
          lines.push(word);
          current = '';
        }
      }
    }
  }
  if (current) lines.push(current);
  return lines.join('\n');
}

export function stripHtml(input) {
  let s = toStr(input);
  if (!s) return '';
  // Remove tags
  s = s.replace(/<[^>]*>/g, '');
  // Decode a few common entities
  const map = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&nbsp;': ' '
  };
  s = s.replace(/&[a-zA-Z0-9#]+;/g, (entity) => map[entity] ?? entity);
  return s;
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return '';
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

export function pluralize(input) {
  const s = toStr(input).trim();
  if (!s) return '';
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/.test(lower)) return s + 'es';
  if (/[^aeiou]y$/.test(lower)) return s.slice(0, -1) + 'ies';
  if (/fe$/.test(lower)) return s.slice(0, -2) + 'ves';
  if (/f$/.test(lower)) return s.slice(0, -1) + 'ves';
  return s + 's';
}

export function levenshtein(a, b) {
  const sa = toStr(a);
  const sb = toStr(b);
  if (sa === sb) return 0;
  const aArr = Array.from(sa);
  const bArr = Array.from(sb);
  const n = aArr.length;
  const m = bArr.length;
  if (n === 0) return m;
  if (m === 0) return n;
  let prev = new Array(m + 1);
  let curr = new Array(m + 1);
  for (let j = 0; j <= m; j++) prev[j] = j;
  for (let i = 1; i <= n; i++) {
    curr[0] = i;
    for (let j = 1; j <= m; j++) {
      const cost = aArr[i - 1] === bArr[j - 1] ? 0 : 1;
      curr[j] = Math.min(
        prev[j] + 1,     // deletion
        curr[j - 1] + 1, // insertion
        prev[j - 1] + cost // substitution
      );
    }
    [prev, curr] = [curr, prev];
  }
  return prev[m];
}
